var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"선장, 또 이 시간에 나만 불러낸 거야?","JPN":"船長、またこんな時間にあたしだけ呼び出し？","ENG":"Captain, did you call just me again at this hour?","TWN":"船長，你又在這個時間只叫了我嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이번에도 역시 그걸 해주면 되는 거지?","JPN":"今回もあれをしてほしいんだな？","ENG":"You want me to do that thing again, right?","TWN":"這次也是要我做那件事吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"잔뜩 굳어버린 부위를 부드럽게 풀어주는…….","JPN":"カチカチになった部位を柔らかくほぐす……","ENG":"Loosening up all those stiff spots that've locked up...?","TWN":"幫你慢慢放鬆僵硬地方的……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"안마 말이야.","JPN":"マッサージ。","ENG":"You know. A massage.","TWN":"按摩，對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"응? 말을 할 때는 주어를 반드시 앞에……?","JPN":"ん？　何か言うときは主語をつけろって……？","ENG":"Huh? When I talk, I should always put the subject first...?","TWN":"嗯？說話時主詞一定要放前面……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"무슨 말인지 모르겠고, 이번엔 어디를 주물러줄까?","JPN":"何のことだかわかんないけど、とにかくどこを揉んでほしいんだ？","ENG":"I don't really get it, but anyway, where do you want me to work on this time?","TWN":"我聽不懂啦。所以這次要我按哪裡？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…종신 계약이라고?\xA0","JPN":"……終身契約？","ENG":"...A lifetime contract?","TWN":"……終身雇傭？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"선장. 나는 해적이야.","JPN":"船長。あたしは海賊だぞ。","ENG":"Captain. I'm a pirate.","TWN":"船長，我可是海盜。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이까짓 종이 쪼가리에 서명한다고 해서, 나를 옭아맬 수는 없다는 소리지.","JPN":"こんな紙切れに署名したところで、あたしを縛り付けるなんて無理な話さ。","ENG":"Signing some flimsy piece of paper like this isn't going to bind me.","TWN":"不是在這種紙上簽個名，就能束縛我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"응? 그럴 일은 절대 없을 거라고?","JPN":"ん？　そんなことは絶対しない？","ENG":"Huh? You swear that'll never happen?","TWN":"嗯？你說絕對不會那樣？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나, 나 같이 강인한 해적은 속박할 수 있는 사람이 아니니 그저 곁에 두고 싶었다고?","JPN":"あ、あたしのような強い海賊はそもそも束縛が通じる人じゃないから、ただそばに置きたいだけ？","ENG":"Th-That a strong pirate like me can't be tied down, and you just wanted me by your side?","TWN":"像、像我這樣強悍的海盜，本來就不可能被束縛，所以只是想把我留在身邊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"하,하핫!진작그렇게말을하지그랬어?부끄럽게나혼자분위기잡고으르렁거렸잖아?!","JPN":"は、ははっ！　そうならそうと最初っから言えよ。一人で格好つけていらねえこと言っちまったじゃねえか！？","ENG":"Ha, haha! You could've just said that sooner! You had me all embarrassed, working myself up and growling for nothing!","TWN":"哈、哈哈！那你怎麼不早說啊？害我一個人在那邊營造氣氛、大聲咆哮，丟臉死了啦？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"선장도 잘 알고 있겠지만, 내 목표는 대해적이 되는 거야.","JPN":"船長も知っての通り、あたしの夢は大海賊になることだ。","ENG":"You know this already, Captain, but my goal is to become the great pirate.","TWN":"船長你也知道，我的目標是成為大海盜。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"바다를 항해하며 수많은 전설을 만들고… 모두에게 대해적으로 인정받는 거지.","JPN":"海を航海しながら数多くの伝説を生み出して……みんなに大海賊として認めてもらう。","ENG":"Sailing the seas, creating countless legends... And being recognized by everyone as the great pirate.","TWN":"在海上航行，創造無數傳說……被所有人認可的大海盜。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"당신과 함께하면서 많은 것을 느끼게 되었어.","JPN":"あんたといる間、色んなことに気づいたよ。","ENG":"Sailing with you, I've come to realize a lot of things.","TWN":"和你同行後，我感受到很多。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나 혼자서는 한치 앞도 보이지 않는… 어두운 바다를 헤쳐 나갈 수 없다는 것을.","JPN":"あたし一人じゃ、一歩先も見えない……真っ暗な海を渡ることはできないってこと。","ENG":"That on my own... I can't make it through that dark sea, not even a step ahead.","TWN":"靠我自己一個人……無法穿越那片連前方都看不見的黑暗海域。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"내가 대해적이 되기 위해선… 선장, 당신의 도움이 필요하다는 것을.","JPN":"あたしが大海賊になるためには……船長、あんたの助けが必要だってこと。","ENG":"If I'm going to become a great pirate... Captain, I need your help.","TWN":"為了成為大海盜…… 船長，我需要你的幫助。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이런 종이 계약서 따윈 필요 없어.","JPN":"こんな紙切れの契約書なんて要らない。","ENG":"I don't need some paper contract like this.","TWN":"根本不需要這種紙本契約。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"난 이미 마음을 정했으니까.","JPN":"あたしはもう決めたから。","ENG":"That's because I've already made up my mind.","TWN":"因為我早就下定決心了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"승선을 허락해줘, 선장.","JPN":"乗船を許可してくれ、船長。","ENG":"Let me come aboard, Captain.","TWN":"請允許我登船吧，船長。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};